<template><div class="login"><el-card class="login-box"><h2>意图驱动网络策略管理系统</h2><el-form :model="form"><el-form-item><el-input v-model="form.username" placeholder="用户名"/></el-form-item><el-form-item><el-input v-model="form.password" show-password placeholder="密码"/></el-form-item><el-button type="primary" style="width:100%" @click="login">登录</el-button></el-form><p class="muted">管理员：admin / Admin@123456<br>操作员：operator / Operator@123456<br>审计员：auditor / Auditor@123456</p></el-card></div></template>
<script setup>import{reactive}from'vue';import{useRouter}from'vue-router';import{ElMessage}from'element-plus';import{api}from'../api/http';const router=useRouter();const form=reactive({username:'admin',password:'Admin@123456'});async function login(){try{const r=await api.post('/login',form);localStorage.setItem('user',JSON.stringify(r.data));router.push('/')}catch(e){ElMessage.error('账号或密码错误')}}</script>